#include "laser_module.h"
#include <Arduino.h>
#define LASER_PIN 25
void laser_setup(){pinMode(LASER_PIN,OUTPUT);Serial.println("[laser] OK");}
void laser_on(){digitalWrite(LASER_PIN,HIGH);}
void laser_off(){digitalWrite(LASER_PIN,LOW);}
void laser_blink(uint16_t ms){laser_on();delay(ms);laser_off();}
